/**
 * Generated by `createservice acquiring.RegisterExternalPaymentsService`
 */
const Big = require('big.js')

const { GQLError } = require('@open-condo/keystone/errors')
const { checkDvAndSender } = require('@open-condo/keystone/plugins/dvAndSender')
const { GQLCustomSchema, getByCondition, find } = require('@open-condo/keystone/schema')

const access = require('@condo/domains/acquiring/access/RegisterExternalPaymentsService')
const { CONTEXT_FINISHED_STATUS } = require('@condo/domains/acquiring/constants/context')
const { ACQUIRING_INTEGRATION_EXTERNAL_IMPORT_TYPE } = require('@condo/domains/acquiring/constants/integration')
const {
    DEFAULT_MULTIPAYMENT_SERVICE_CATEGORY,
    MULTIPAYMENT_DONE_STATUS,
    PAYMENT_DONE_STATUS,
} = require('@condo/domains/acquiring/constants/payment')
const { ERRORS, PAYMENTS_LIMIT } = require('@condo/domains/acquiring/constants/registerExternalPayments')
const { Payment, MultiPayment } = require('@condo/domains/acquiring/utils/serverSchema')
const { DEFAULT_CURRENCY_CODE, ISO_CODES } = require('@condo/domains/common/constants/currencies')

function calculateMultiPaymentAmounts (payment) {
    const fields = ['amount', 'explicitFee', 'explicitServiceCharge', 'serviceFee', 'implicitFee']
    const result = {}

    fields.forEach(field => {
        const value = Big(payment[field] || 0)
        result[field === 'amount' ? 'amountWithoutExplicitFee' : field] = value.toFixed(2)
    })

    return result
}

function validateMoney (value) {

}

function validatePayment (payment) {

}

const RegisterExternalPaymentsService = new GQLCustomSchema('RegisterExternalPaymentsService', {
    types: [
        {
            access: true,
            type: 'input ExternalPaymentsInput { accountNumber: String!, tin: String!, bankAccount: String!, routingNumber: String!, address: String!, period: String!, depositedDate: String, transactionDate: String!, transactionId: String!, amount: String!, explicitFee: String, implicitFee: String, paymentOrder: String!, currencyCode: String! }',
        },
        {
            access: true,
            type: 'input RegisterExternalPaymentsInput { dv: Int!, sender: JSON!, acquiringIntegrationContext: AcquiringIntegrationContextWhereUniqueInput!, payments: [ExternalPaymentsInput!]! }',
        },
        {
            access: true,
            type: 'type RegisterExternalPaymentsOutput { status: String! }',
        },
    ],

    mutations: [
        {
            access: access.canRegisterExternalPayments,
            schema: 'registerExternalPayments(data: RegisterExternalPaymentsInput!): RegisterExternalPaymentsOutput',
            doc: {
                summary: 'Registers external payments received from third-party sources',
                description: 'Creates a chain of Payment and MultiPayment objects with DONE status. Used to synchronize registries.',
                errors: ERRORS,
            },
            resolver: async (parent, args, context) => {
                const { data } = args
                const { sender, payments: paymentsInput, acquiringIntegrationContext: acquiringContextInput } = data

                checkDvAndSender(data, ERRORS.DV_VERSION_MISMATCH, ERRORS.WRONG_SENDER_FORMAT, context)

                if (paymentsInput.length > PAYMENTS_LIMIT) throw new GQLError(ERRORS.PAYMENTS_LIMIT_EXCEEDED, context)

                const externalIds = paymentsInput.map(p => p.transactionId)
                if (new Set(externalIds).size !== externalIds.length) {
                    throw new GQLError(ERRORS.DUPLICATED_PAYMENTS, context)
                }

                const { id: acquiringContextId } = acquiringContextInput
                const acquiringContext = await getByCondition('AcquiringIntegrationContext', {
                    id: acquiringContextId,
                    status: CONTEXT_FINISHED_STATUS,
                    deletedAt: null,
                })

                if (!acquiringContext) throw new GQLError(ERRORS.ACQUIRING_CONTEXT_NOT_FOUND, context)

                const acquiringIntegration = await getByCondition('AcquiringIntegration', {
                    id: acquiringContext.integration,
                    type: ACQUIRING_INTEGRATION_EXTERNAL_IMPORT_TYPE,
                    deletedAt: null,
                })

                if (!acquiringIntegration) throw new GQLError(ERRORS.ACQUIRING_INTEGRATION_NOT_FOUND, context)

                const existingMultiPayments = await find('MultiPayment', {
                    transactionId_in: externalIds,
                    integration: { id: acquiringIntegration.id },
                    deletedAt: null,
                })

                if (existingMultiPayments.length > 0) {
                    const duplicateIds = existingMultiPayments.map(p => p.transactionId).join(', ')
                    throw new GQLError({ ...ERRORS.DUPLICATED_PAYMENTS, messageInterpolation: { ids: duplicateIds } }, context)
                }

                const paymentsToCreate = paymentsInput.map(paymentInput => {
                    if (!validatePayment(paymentInput)) {
                        throw new GQLError({
                            ...ERRORS.INVALID_PARAMS,
                            messageInterpolation: {
                                details: ajv.errorsText(validatePayment.errors),
                                transactionId: paymentInput.transactionId,
                            },
                        }, context)
                    }

                    const amount = Big(paymentInput.amount)
                    const explicitFee = Big(paymentInput.explicitFee || 0)
                    const implicitFee = Big(paymentInput.implicitFee || 0)

                    if (amount.lte(0)) {
                        throw new GQLError({
                            ...ERRORS.NEGATIVE_PAYMENT_AMOUNT,
                            messageInterpolation: { amount: paymentInput.amount, transactionId: paymentInput.transactionId },
                        }, context)
                    }
                    if (explicitFee.lt(0) || implicitFee.lt(0)) {
                        throw new GQLError(ERRORS.INVALID_PARAMS, context)
                    }
                    if (explicitFee.plus(implicitFee).gte(amount)) {
                        throw new GQLError(ERRORS.INVALID_PARAMS, context)
                    }

                    return {
                        dv: 1,
                        sender,
                        status: PAYMENT_DONE_STATUS,
                        amount: amount.toFixed(2),
                        currencyCode: ISO_CODES.includes(paymentInput.currencyCode) ? paymentInput.currencyCode : DEFAULT_CURRENCY_CODE,
                        accountNumber: paymentInput.accountNumber,
                        period: paymentInput.period,
                        context: { connect: { id: acquiringContextId } },
                        organization: { connect: { id: acquiringContext.organization } },
                        recipientBic: paymentInput.routingNumber,
                        recipientBankAccount: paymentInput.bankAccount,
                        advancedAt: paymentInput.transactionDate,
                        depositedDate: paymentInput.depositedDate,
                        explicitFee: explicitFee.toFixed(2),
                        implicitFee: implicitFee.toFixed(2),
                        rawAddress: paymentInput.address,
                        order: paymentInput.paymentOrder,
                        importId: paymentInput.transactionId,
                    }
                })

                const createdPayments = await Promise.all(
                    paymentsToCreate.map(p => Payment.create(context, p, 'id currencyCode amount explicitFee explicitServiceCharge serviceFee implicitFee importId advancedAt'))
                )

                const multiPaymentsToCreate = createdPayments.map(payment => ({
                    dv: 1,
                    sender,
                    ...calculateMultiPaymentAmounts(payment),
                    currencyCode: payment.currencyCode,
                    integration: { connect: { id: acquiringIntegration.id } },
                    payments: { connect: [{ id: payment.id }] },
                    serviceCategory: DEFAULT_MULTIPAYMENT_SERVICE_CATEGORY,
                    status: MULTIPAYMENT_DONE_STATUS,
                    cardNumber: 'IMPORT',
                    paymentWay: 'IMPORT',
                    transactionId: payment.importId,
                    withdrawnAt: payment.advancedAt,
                }))

                await Promise.all(multiPaymentsToCreate.map(mp => MultiPayment.create(context, mp)))

                return { status: 'ok' }
            },
        },
    ],
})

module.exports = {
    RegisterExternalPaymentsService,
}